import * as React from 'react';
import { createComponent } from '../create-component.js';
import Component from '../../components/breadcrumb-item/src/breadcrumb-item.component.js';
const tagName = 'made-breadcrumb-item';
Component.define('made-breadcrumb-item');
/**
 * @summary A breadcrumb item represents a single link within a breadcrumb navigation trail.
 * @documentation '../../components/breadcrumb-item/stories/breadcrumb-item.mdx'
 *
 * @slot - The breadcrumb item's content. When provided, it will be used instead of the built-in made-link.
 *
 * @csspart base - The component's base wrapper (wraps the made-link or slotted content).
 * @csspart link - The underlying made-link element (only when using prop-based API).
 * @csspart link-base - The base part of the made-link (only when using prop-based API).
 * @csspart link-label - The label part of the made-link (only when using prop-based API).
 * @csspart current - The wrapper for the current page item (only when current is true and using prop-based API).
 */
const reactWrapper = createComponent({
    tagName,
    elementClass: Component,
    react: React,
    events: {},
    displayName: 'MadeBreadcrumbItem'
});
export default reactWrapper;
